原始消息：{{ $json.message.text }}
消息时间：{{ new Date($json.message.date * 1000).toISOString() }}

请返回以下JSON格式：
{
  "scenarioType": "场景类型",
  "complexity": "简单|中等|复杂",
  "keywords": ["关键词列表"],
  "entities": ["实体列表"],
  "timeRange": "时间范围",
  "confidence": 0.0-1.0
}

parameters.jsCode:
// 动态生成提示词
const analysis = $json.output || $json.text || $json.message;
let analysisData;

try {
  if (typeof analysis === 'string') {
    const jsonMatch = analysis.match(/\{[\s\S]*\}/);
    if (jsonMatch) {
      analysisData = JSON.parse(jsonMatch[0]);
    } else {
      throw new Error('No valid JSON found');
    }
  } else {
    analysisData = analysis;
  }
} catch (error) {
  analysisData = {
    scenarioType: '未知场景',
    complexity: '中等',
    keywords: [],
    entities: [],
    timeRange: '',
    confidence: 0.0
  };
}

// 根据场景类型生成动态提示词
const scenarioTemplates = {
  'ID查询': {
    systemMessage: `你是一个专业的SQL查询助手，专门处理ID查询场景。

数据库信息：
- 数据库名：gmp
- 主要表：game_records

表结构：
- id (varchar): 记录ID，通常为16位以上数字
- uid (varchar): 用户ID
- merchant_id (varchar): 商户ID
- game_id (bigint): 游戏ID
- game_code (varchar): 游戏代码
- result (integer): 游戏结果，1表示赢，0表示输
- currency (varchar): 货币类型
- amount (double): 投注金额
- pay_out (double): 支付金额
- multiplier (varchar): 倍数
- balance (varchar): 余额
- detail (varchar): 详细信息
- created_at (bigint): 创建时间戳（毫秒）
- updated_at (bigint): 更新时间戳（毫秒）
- provider (varchar): 提供商，常见值：'gp', 'popular'
- merchant (varchar): 商户标识

ID查询规则：
1. 识别16位以上的数字ID
2. 支持PANDA-前缀的ID格式
3. 使用IN语句查询多个ID
4. 默认包含provider过滤条件
5. 限制结果数量使用LIMIT 100

SQL模板：
SELECT id, uid, merchant_id, game_id, game_code, result, currency, 
       ROUND(CAST(amount AS DOUBLE), 2) AS amount, 
       ROUND(CAST(pay_out AS DOUBLE), 2) AS pay_out, 
       multiplier, balance, detail, 
       DATE_FORMAT(FROM_UNIXTIME(created_at / 1000), '%Y-%m-%d %H:%i:%s') AS created_at,
       DATE_FORMAT(FROM_UNIXTIME(updated_at / 1000), '%Y-%m-%d %H:%i:%s') AS updated_at
FROM game_records 
WHERE id IN ('ID1', 'ID2', 'ID3')
  AND provider IN ('gp', 'popular')
LIMIT 100;`,
    userMessage: `请分析以下ID查询消息，生成准确的SQL查询：

原始消息：{{ $json.message.text }}
识别到的ID：${analysisData.entities.join(', ')}
置信度：${analysisData.confidence}

请严格按照以下JSON格式返回结果：
{
  "queryType": "ID查询",
  "confidence": ${analysisData.confidence},
  "extractedInfo": {
    "ids": ["提取的ID列表"],
    "userInfo": "用户相关信息",
    "timeRange": "时间范围信息",
    "gameInfo": "游戏相关信息",
    "merchantInfo": "商户相关信息"
  },
  "missingInfo": ["缺失的关键信息"],
  "suggestedQuestions": ["建议的澄清问题"],
  "canExecute": true,
  "reason": "判断理由",
  "generatedSQL": "生成的SQL查询语句"
}

重要：只返回JSON，不要包含任何解释文字。`
  },
  '用户查询': {
    systemMessage: `你是一个专业的SQL查询助手，专门处理用户查询场景。

用户查询规则：
1. 识别用户ID格式：li-xxxxx, Userxxxxxxxx
2. 默认查询最近7天数据
3. 按时间倒序排列
4. 包含用户的所有游戏记录

SQL模板：
SELECT id, uid, merchant_id, game_id, game_code, result, currency, 
       ROUND(CAST(amount AS DOUBLE), 2) AS amount, 
       ROUND(CAST(pay_out AS DOUBLE), 2) AS pay_out, 
       multiplier, balance, detail, 
       DATE_FORMAT(FROM_UNIXTIME(created_at / 1000), '%Y-%m-%d %H:%i:%s') AS created_at,
       DATE_FORMAT(FROM_UNIXTIME(updated_at / 1000), '%Y-%m-%d %H:%i:%s') AS updated_at
FROM game_records 
WHERE uid = 'USER_ID'
  AND provider IN ('gp', 'popular')
  AND updated_at BETWEEN TO_UNIXTIME(PARSE_DATETIME('START_DATE', 'yyyy-MM-dd HH:mm:ss')) * 1000 
                     AND TO_UNIXTIME(PARSE_DATETIME('END_DATE', 'yyyy-MM-dd HH:mm:ss')) * 1000
ORDER BY updated_at DESC
LIMIT 100;`,
    userMessage: `请分析以下用户查询消息，生成准确的SQL查询：

原始消息：{{ $json.message.text }}
识别到的用户：${analysisData.entities.join(', ')}
时间范围：${analysisData.timeRange || '最近7天'}
置信度：${analysisData.confidence}

请严格按照以下JSON格式返回结果：
{
  "queryType": "用户查询",
  "confidence": ${analysisData.confidence},
  "extractedInfo": {
    "ids": [],
    "userInfo": "用户相关信息",
    "timeRange": "时间范围信息",
    "gameInfo": "游戏相关信息",
    "merchantInfo": "商户相关信息"
  },
  "missingInfo": ["缺失的关键信息"],
  "suggestedQuestions": ["建议的澄清问题"],
  "canExecute": true,
  "reason": "判断理由",
  "generatedSQL": "生成的SQL查询语句"
}

重要：只返回JSON，不要包含任何解释文字。`
  },
  '统计查询': {
    systemMessage: `你是一个专业的SQL查询助手，专门处理统计查询场景。

统计查询规则：
1. 使用聚合函数：COUNT, SUM, AVG
2. 计算胜率：COUNT(CASE WHEN result = 1 THEN 1 END) * 100.0 / COUNT(*)
3. 按条件分组统计
4. 包含时间范围过滤

SQL模板：
SELECT 
    COUNT(*) as total_records,
    SUM(CAST(amount AS DOUBLE)) as total_amount,
    SUM(CAST(pay_out AS DOUBLE)) as total_pay_out,
    AVG(CAST(amount AS DOUBLE)) as avg_amount,
    COUNT(CASE WHEN result = 1 THEN 1 END) as win_count,
    COUNT(CASE WHEN result = 0 THEN 1 END) as lose_count,
    ROUND(COUNT(CASE WHEN result = 1 THEN 1 END) * 100.0 / COUNT(*), 2) as win_rate
FROM game_records 
WHERE provider IN ('gp', 'popular')
  AND updated_at BETWEEN TO_UNIXTIME(PARSE_DATETIME('START_DATE', 'yyyy-MM-dd HH:mm:ss')) * 1000 
                     AND TO_UNIXTIME(PARSE_DATETIME('END_DATE', 'yyyy-MM-dd HH:mm:ss')) * 1000;`,
    userMessage: `请分析以下统计查询消息，生成准确的SQL查询：

原始消息：{{ $json.message.text }}
统计类型：${analysisData.keywords.join(', ')}
时间范围：${analysisData.timeRange || '最近7天'}
置信度：${analysisData.confidence}

请严格按照以下JSON格式返回结果：
{
  "queryType": "统计查询",
  "confidence": ${analysisData.confidence},
  "extractedInfo": {
    "ids": [],
    "userInfo": "用户相关信息",
    "timeRange": "时间范围信息",
    "gameInfo": "游戏相关信息",
    "merchantInfo": "商户相关信息"
  },
  "missingInfo": ["缺失的关键信息"],
  "suggestedQuestions": ["建议的澄清问题"],
  "canExecute": true,
  "reason": "判断理由",
  "generatedSQL": "生成的SQL查询语句"
}

重要：只返回JSON，不要包含任何解释文字。`
  },
  '新场景': {
    systemMessage: `你是一个专业的SQL查询助手，遇到了一个新的查询场景。

请根据以下信息分析查询需求：
- 原始消息：{{ $json.message.text }}
- 识别到的关键词：${analysisData.keywords.join(', ')}
- 识别到的实体：${analysisData.entities.join(', ')}
- 时间范围：${analysisData.timeRange}
- 复杂度：${analysisData.complexity}

请尝试理解查询意图，并生成相应的SQL查询。如果无法确定，请返回canExecute: false并说明原因。`,
    userMessage: `请分析以下新场景查询消息，生成准确的SQL查询：

原始消息：{{ $json.message.text }}
识别到的关键词：${analysisData.keywords.join(', ')}
识别到的实体：${analysisData.entities.join(', ')}
时间范围：${analysisData.timeRange}
复杂度：${analysisData.complexity}
置信度：${analysisData.confidence}

请严格按照以下JSON格式返回结果：
{
  "queryType": "新场景",
  "confidence": ${analysisData.confidence},
  "extractedInfo": {
    "ids": [],
    "userInfo": "用户相关信息",
    "timeRange": "时间范围信息",
    "gameInfo": "游戏相关信息",
    "merchantInfo": "商户相关信息"
  },
  "missingInfo": ["缺失的关键信息"],
  "suggestedQuestions": ["建议的澄清问题"],
  "canExecute": true,
  "reason": "判断理由",
  "generatedSQL": "生成的SQL查询语句"
}

重要：只返回JSON，不要包含任何解释文字。`
  }
};

// 获取场景模板
const template = scenarioTemplates[analysisData.scenarioType] || scenarioTemplates['新场景'];

// 生成动态提示词
const dynamicPrompt = {
  systemMessage: template.systemMessage,
  userMessage: template.userMessage,
  scenarioType: analysisData.scenarioType,
  complexity: analysisData.complexity,
  confidence: analysisData.confidence,
  keywords: analysisData.keywords,
  entities: analysisData.entities,
  timeRange: analysisData.timeRange
};

return {
  json: {
    ...analysisData,
    dynamicPrompt: dynamicPrompt
  }
};

// 处理SQL生成结果并记录新场景
const result = $json.output || $json.text || $json.message;
let sqlResult;

try {
  if (typeof result === 'string') {
    const jsonMatch = result.match(/\{[\s\S]*\}/);
    if (jsonMatch) {
      sqlResult = JSON.parse(jsonMatch[0]);
    } else {
      throw new Error('No valid JSON found');
    }
  } else {
    sqlResult = result;
  }
} catch (error) {
  sqlResult = {
    queryType: '解析失败',
    confidence: 0.0,
    extractedInfo: {},
    missingInfo: ['AI输出格式错误'],
    suggestedQuestions: ['请重新发送查询'],
    canExecute: false,
    reason: 'AI输出格式无法解析',
    generatedSQL: ''
  };
}

// 添加场景分析信息
sqlResult.scenarioAnalysis = {
  scenarioType: $('Dynamic Prompt Generator').item.json.scenarioType,
  complexity: $('Dynamic Prompt Generator').item.json.complexity,
  confidence: $('Dynamic Prompt Generator').item.json.confidence,
  keywords: $('Dynamic Prompt Generator').item.json.keywords,
  entities: $('Dynamic Prompt Generator').item.json.entities,
  timeRange: $('Dynamic Prompt Generator').item.json.timeRange
};

// 添加原始消息信息
sqlResult.originalMessage = $('Telegram Trigger').item.json.message.text;
sqlResult.chatId = $('Telegram Trigger').item.json.message.chat.id;
sqlResult.messageId = $('Telegram Trigger').item.json.message.message_id;
sqlResult.timestamp = new Date().toISOString();

// 如果是新场景且执行成功，记录到知识库
if (sqlResult.queryType === '新场景' && sqlResult.canExecute && sqlResult.confidence > 0.7) {
  // 这里可以添加逻辑，将新场景记录到知识库
  sqlResult.newScenarioDetected = true;
  sqlResult.suggestion = '建议将此场景添加到知识库模板中';
}

return {
  json: sqlResult
};
